function navegacionFija() {
    const barra = document.querySelector('.navegacion-principal');

    //Registrar el objeto Intersection Observer que es para ver que elemento esta en pantalla
    const observar = new IntersectionObserver(function (entries) {
        if (entries[0].isIntersecting) {
            barra.classList.remove('fijo');
        } else {
            barra.classList.add('fijo');
        }
    })

    //Elemento a observar
    observar.observe(document.querySelector('.header'))
}

